     1→/**
     2→ * Form Renderer Component
     3→ * Renders form fields from template and handles submission
     4→ */
     5→
     6→import { useState, useMemo } from 'react';
     7→import type { FormTemplate, FormValidationResult, ConditionalRule, DependentValidation, FormField, FieldType } from '../../types/forms';
     8→import { evaluateFormula } from '../../utils/formulaEngine';
     9→import { replaceAnswerTokens } from '../../utils/answerPiping';
    10→import {
    11→  TextField,
    12→  TextAreaField,
    13→  NumberField,
    14→  DateField,
    15→  TimeField,
    16→  SelectField,
    17→  MultiSelectField,
    18→  RadioField,
    19→  CheckboxField,
    20→  RatingField,
    21→  ScaleField,
    22→  FileUploadField,
    23→} from './FieldComponents';
    24→
    25→interface FormRendererProps {
    26→  form: FormTemplate;
    27→  onSubmit: (
    28→    answers: Record<string, any>,
    29→    metadata?: {
    30→      isSpam?: boolean;
    31→      submissionTimeSeconds?: number;
    32→      score?: number;
    33→      maxScore?: number;
    34→    }
    35→  ) => void;
    36→  initialValues?: Record<string, any>;
    37→}
    38→
    39→export function FormRenderer({ form, onSubmit, initialValues = {} }: FormRendererProps) {
    40→  // Parse URL parameters for hidden fields
    41→  const urlParams = useMemo(() => {
    42→    const params = new URLSearchParams(window.location.search);
    43→    const parsedParams: Record<string, string> = {};
    44→    params.forEach((value, key) => {
    45→      parsedParams[key] = value;
    46→    });
    47→    return parsedParams;
    48→  }, []);
    49→
    50→  // Initialize answers with URL parameters for hidden fields
    51→  const [answers, setAnswers] = useState<Record<string, any>>(() => {
    52→    const initialAnswers = { ...initialValues };
    53→
    54→    // Auto-fill hidden fields from URL parameters
    55→    form.fields.forEach((field) => {
    56→      if (field.type === 'hidden' && urlParams[field.label]) {
    57→        initialAnswers[field.id] = urlParams[field.label];
    58→      }
    59→    });
    60→
    61→    return initialAnswers;
    62→  });
    63→
    64→  const [errors, setErrors] = useState<Record<string, string>>({});
    65→  const [formLoadTime] = useState(Date.now()); // Track when form was loaded
    66→  const [honeypot, setHoneypot] = useState(''); // Honeypot field value
    67→
    68→  /**
    69→   * Calculate values for calculated fields
    70→   * Returns a map of calculated field IDs to their computed values
    71→   */
    72→  const calculatedValues = useMemo(() => {
    73→    const calculated: Record<string, any> = {};
    74→
    75→    form.fields.forEach((field) => {
    76→      if (field.type === 'calculation' && field.calculationSettings) {
    77→        const { formula, decimalPlaces } = field.calculationSettings;
    78→
    79→        // Evaluate formula using current field values
    80→        const result = evaluateFormula(formula, answers);
    81→
    82→        if (!result.error && result.value !== null && result.value !== undefined) {
    83→          // Format number values based on decimal places
    84→          if (typeof result.value === 'number' && decimalPlaces !== undefined) {
    85→            calculated[field.id] = result.value % 1 === 0
    86→              ? result.value
    87→              : Number(result.value.toFixed(decimalPlaces));
    88→          } else {
    89→            calculated[field.id] = result.value;
    90→          }
    91→        }
    92→      }
    93→    });
    94→
    95→    return calculated;
    96→  }, [form.fields, answers]);
    97→
    98→  /**
    99→   * Evaluate conditional rules to determine which fields should be visible
   100→   * Returns a Set of field IDs that should be shown
   101→   */
   102→  const visibleFieldIds = useMemo(() => {
   103→    const visible = new Set<string>();
   104→
   105→    // Merge answers with calculated values for conditional evaluation
   106→    const allValues = { ...answers, ...calculatedValues };
   107→
   108→    form.fields.forEach((field) => {
   109→      // If no conditional rules, field is always visible
   110→      if (!field.conditionalRules || field.conditionalRules.length === 0) {
   111→        visible.add(field.id);
   112→        return;
   113→      }
   114→
   115→      // Evaluate all rules - field is shown if ANY rule evaluates to 'show' (OR logic)
   116→      const shouldShow = field.conditionalRules.some((rule) =>
   117→        evaluateConditionalRule(rule, allValues)
   118→      );
   119→
   120→      if (shouldShow) {
   121→        visible.add(field.id);
   122→      }
   123→    });
   124→
   125→    return visible;
   126→  }, [form.fields, answers, calculatedValues]);
   127→
   128→  /**
   129→   * Calculate form completion progress
   130→   * Only counts visible fields (respects conditional logic)
   131→   */
   132→  const progress = useMemo(() => {
   133→    if (!form.settings.showProgressBar) return 0;
   134→
   135→    const visibleFields = form.fields.filter((f) => visibleFieldIds.has(f.id));
   136→    if (visibleFields.length === 0) return 0;
   137→
   138→    const answeredFields = visibleFields.filter((field) => {
   139→      const answer = answers[field.id];
   140→
   141→      // Check if field has a valid answer
   142→      if (answer === undefined || answer === null || answer === '') return false;
   143→      if (Array.isArray(answer) && answer.length === 0) return false;
   144→
   145→      return true;
   146→    });
   147→
   148→    return Math.round((answeredFields.length / visibleFields.length) * 100);
   149→  }, [form.fields, form.settings.showProgressBar, visibleFieldIds, answers]);
   150→
   151→  const handleFieldChange = (fieldId: string, value: any) => {
   152→    setAnswers({ ...answers, [fieldId]: value });
   153→    // Clear error when user starts typing
   154→    if (errors[fieldId]) {
   155→      setErrors({ ...errors, [fieldId]: '' });
   156→    }
   157→  };
   158→
   159→  const validateForm = (): FormValidationResult => {
   160→    const newErrors: Record<string, string> = {};
   161→
   162→    // Merge answers with calculated values for validation
   163→    const allValues = { ...answers, ...calculatedValues };
   164→
   165→    form.fields.forEach((field) => {
   166→      // Skip validation for hidden fields (conditional logic)
   167→      if (!visibleFieldIds.has(field.id)) {
   168→        return;
   169→      }
   170→
   171→      // Skip validation for calculated fields (they are read-only)
   172→      if (field.type === 'calculation') {
   173→        return;
   174→      }
   175→
   176→      const value = answers[field.id];
   177→
   178→      // Required validation
   179→      if (field.required) {
   180→        if (value === undefined || value === null || value === '') {
   181→          newErrors[field.id] = 'This field is required';
   182→        } else if (Array.isArray(value) && value.length === 0) {
   183→          newErrors[field.id] = 'Please select at least one option';
   184→        }
   185→      }
   186→
   187→      // Number validation
   188→      if (field.type === 'number' && value !== null && value !== undefined && value !== '') {
   189→        if (field.validation?.min !== undefined && Number(value) < field.validation.min) {
   190→          newErrors[field.id] = `Minimum value is ${field.validation.min}`;
   191→        }
   192→        if (field.validation?.max !== undefined && Number(value) > field.validation.max) {
   193→          newErrors[field.id] = `Maximum value is ${field.validation.max}`;
   194→        }
   195→      }
   196→
   197→      // Dependent validation
   198→      if (field.dependentValidation && field.dependentValidation.length > 0) {
   199→        for (const validation of field.dependentValidation) {
   200→          const error = evaluateDependentValidation(validation, value, allValues);
   201→          if (error) {
   202→            newErrors[field.id] = error;
   203→            break; // Stop at first error
   204→          }
   205→        }
   206→      }
   207→    });
   208→
   209→    return {
   210→      isValid: Object.keys(newErrors).length === 0,
   211→      errors: newErrors,
   212→    };
   213→  };
   214→
   215→  const handleSubmit = (e: React.FormEvent) => {
   216→    e.preventDefault();
   217→
   218→    const validation = validateForm();
   219→
   220→    if (!validation.isValid) {
   221→      setErrors(validation.errors);
   222→      // Scroll to first error
   223→      const firstErrorField = form.fields.find((field) => validation.errors[field.id]);
   224→      if (firstErrorField) {
   225→        const element = document.getElementById(`field-${firstErrorField.id}`);
   226→        element?.scrollIntoView({ behavior: 'smooth', block: 'center' });
   227→      }
   228→      return;
   229→    }
   230→
   231→    // Spam detection (if enabled)
   232→    let isSpam = false;
   233→    let submissionTimeSeconds: number | undefined;
   234→
   235→    if (form.settings.enableSpamProtection) {
   236→      submissionTimeSeconds = (Date.now() - formLoadTime) / 1000;
   237→
   238→      // Honeypot check: if honeypot field has value, it's spam
   239→      if (honeypot !== '') {
   240→        isSpam = true;
   241→      }
   242→
   243→      // Timing check: submissions faster than 2 seconds are suspicious
   244→      if (submissionTimeSeconds < 2) {
   245→        isSpam = true;
   246→      }
   247→    }
   248→
   249→    // Quiz scoring (if quiz mode enabled)
   250→    let score: number | undefined;
   251→    let maxScore: number | undefined;
   252→
   253→    if (form.settings.quizMode) {
   254→      const result = calculateQuizScore(form.fields, answers);
   255→      score = result.score;
   256→      maxScore = result.maxScore;
   257→    }
   258→
   259→    // Pass answers and metadata
   260→    onSubmit(answers, { isSpam, submissionTimeSeconds, score, maxScore });
   261→  };
   262→
   263→  // Sort fields by order
   264→  const sortedFields = [...form.fields].sort((a, b) => a.order - b.order);
   265→
   266→  return (
   267→    <form onSubmit={handleSubmit} className="space-y-6">
   268→      {/* Progress Bar */}
   269→      {form.settings.showProgressBar && (
   270→        <div className="sticky top-0 z-10 bg-background-light dark:bg-background-dark pb-4 -mt-2">
   271→          <div className="flex items-center gap-3">
   272→            <div className="flex-1 h-2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-full overflow-hidden">
   273→              <div
   274→                className="h-full bg-gradient-to-r from-accent-magenta to-accent-cyan transition-all duration-300 ease-out"
   275→                style={{ width: `${progress}%` }}
   276→              />
   277→            </div>
   278→            <span className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary min-w-[4ch]">
   279→              {progress}%
   280→            </span>
   281→          </div>
   282→          {progress > 0 && progress < 100 && (
   283→            <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1 text-center">
   284→              Keep going! {progress}% complete
   285→            </p>
   286→          )}
   287→          {progress === 100 && (
   288→            <p className="text-xs text-green-500 mt-1 text-center">
   289→              ✓ All fields completed! Ready to submit
   290→            </p>
   291→          )}
   292→        </div>
   293→      )}
   294→
   295→      {sortedFields.map((field) => {
   296→        // Skip rendering hidden fields (conditional logic)
   297→        if (!visibleFieldIds.has(field.id)) {
   298→          return null;
   299→        }
   300→
   301→        // Skip rendering hidden field type (they are invisible by design)
   302→        if (field.type === 'hidden') {
   303→          return null;
   304→        }
   305→
   306→        // Render calculated field
   307→        if (field.type === 'calculation' && field.calculationSettings) {
   308→          const calcValue = calculatedValues[field.id];
   309→          const { decimalPlaces, prefix, suffix } = field.calculationSettings;
   310→
   311→          // Format the calculated value
   312→          let displayValue = '';
   313→          if (calcValue !== null && calcValue !== undefined) {
   314→            if (typeof calcValue === 'number') {
   315→              const formatted =
   316→                calcValue % 1 === 0 || decimalPlaces === undefined
   317→                  ? String(calcValue)
   318→                  : calcValue.toFixed(decimalPlaces);
   319→              displayValue = `${prefix || ''}${formatted}${suffix || ''}`;
   320→            } else {
   321→              displayValue = String(calcValue);
   322→            }
   323→          }
   324→
   325→          // Apply answer piping to label and description
   326→          const pipedLabel = replaceAnswerTokens(field.label, answers);
   327→          const pipedDescription = field.description
   328→            ? replaceAnswerTokens(field.description, answers)
   329→            : undefined;
   330→
   331→          return (
   332→            <div key={field.id} id={`field-${field.id}`} className="space-y-2">
   333→              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   334→                {pipedLabel}
   335→                {field.required && <span className="text-red-500 ml-1">*</span>}
   336→              </label>
   337→              {pipedDescription && (
   338→                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   339→                  {pipedDescription}
   340→                </p>
   341→              )}
   342→              <div className="px-4 py-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg">
   343→                <div className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
   344→                  {displayValue || '—'}
   345→                </div>
   346→                <div className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
   347→                  Calculated value
   348→                </div>
   349→              </div>
   350→            </div>
   351→          );
   352→        }
   353→
   354→        // Apply answer piping to field label and description
   355→        const pipedField = {
   356→          ...field,
   357→          label: replaceAnswerTokens(field.label, answers),
   358→          description: field.description ? replaceAnswerTokens(field.description, answers) : undefined,
   359→        };
   360→
   361→        const fieldProps = {
   362→          field: pipedField,
   363→          value: answers[field.id],
   364→          onChange: (value: any) => handleFieldChange(field.id, value),
   365→          error: errors[field.id],
   366→        };
   367→
   368→        return (
   369→          <div key={field.id} id={`field-${field.id}`}>
   370→            {field.type === 'text' && <TextField {...fieldProps} />}
   371→            {field.type === 'textarea' && <TextAreaField {...fieldProps} />}
   372→            {field.type === 'number' && <NumberField {...fieldProps} />}
   373→            {field.type === 'date' && <DateField {...fieldProps} />}
   374→            {field.type === 'time' && <TimeField {...fieldProps} />}
   375→            {field.type === 'select' && <SelectField {...fieldProps} />}
   376→            {field.type === 'multiselect' && <MultiSelectField {...fieldProps} />}
   377→            {field.type === 'radio' && <RadioField {...fieldProps} />}
   378→            {field.type === 'checkbox' && <CheckboxField {...fieldProps} />}
   379→            {field.type === 'rating' && <RatingField {...fieldProps} />}
   380→            {field.type === 'scale' && <ScaleField {...fieldProps} />}
   381→            {field.type === 'file' && <FileUploadField {...fieldProps} />}
   382→          </div>
   383→        );
   384→      })}
   385→
   386→      {/* Honeypot Field (hidden from humans, visible to bots) */}
   387→      {form.settings.enableSpamProtection && (
   388→        <div className="absolute left-[-9999px]" aria-hidden="true">
   389→          <label htmlFor="email_confirm">Email Confirmation</label>
   390→          <input
   391→            type="text"
   392→            id="email_confirm"
   393→            name="email_confirm"
   394→            value={honeypot}
   395→            onChange={(e) => setHoneypot(e.target.value)}
   396→            tabIndex={-1}
   397→            autoComplete="off"
   398→          />
   399→        </div>
   400→      )}
   401→
   402→      <div className="flex justify-end pt-4">
   403→        <button
   404→          type="submit"
   405→          className="px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity font-medium"
   406→        >
   407→          Submit
   408→        </button>
   409→      </div>
   410→    </form>
   411→  );
   412→}
   413→
   414→/**
   415→ * Evaluate a single conditional rule
   416→ * Returns true if the rule evaluates to "show", false if "hide" or condition not met
   417→ */
   418→function evaluateConditionalRule(
   419→  rule: ConditionalRule,
   420→  answers: Record<string, any>
   421→): boolean {
   422→  const triggerValue = answers[rule.fieldId];
   423→
   424→  // Evaluate the condition based on operator
   425→  let conditionMet = false;
   426→
   427→  switch (rule.operator) {
   428→    case 'is_answered':
   429→      conditionMet = triggerValue !== undefined && triggerValue !== null && triggerValue !== '';
   430→      break;
   431→
   432→    case 'is_not_answered':
   433→      conditionMet = triggerValue === undefined || triggerValue === null || triggerValue === '';
   434→      break;
   435→
   436→    case 'equals':
   437→      // Handle array values (multiselect)
   438→      if (Array.isArray(triggerValue)) {
   439→        conditionMet = triggerValue.includes(rule.value);
   440→      } else {
   441→        conditionMet = String(triggerValue) === String(rule.value);
   442→      }
   443→      break;
   444→
   445→    case 'not_equals':
   446→      // Handle array values (multiselect)
   447→      if (Array.isArray(triggerValue)) {
   448→        conditionMet = !triggerValue.includes(rule.value);
   449→      } else {
   450→        conditionMet = String(triggerValue) !== String(rule.value);
   451→      }
   452→      break;
   453→
   454→    case 'contains':
   455→      if (typeof triggerValue === 'string') {
   456→        conditionMet = triggerValue.toLowerCase().includes(String(rule.value).toLowerCase());
   457→      } else if (Array.isArray(triggerValue)) {
   458→        conditionMet = triggerValue.some((v) =>
   459→          String(v).toLowerCase().includes(String(rule.value).toLowerCase())
   460→        );
   461→      }
   462→      break;
   463→
   464→    case 'greater_than':
   465→      conditionMet = Number(triggerValue) > Number(rule.value);
   466→      break;
   467→
   468→    case 'less_than':
   469→      conditionMet = Number(triggerValue) < Number(rule.value);
   470→      break;
   471→
   472→    default:
   473→      conditionMet = false;
   474→  }
   475→
   476→  // Return based on action (show or hide)
   477→  // If action is 'show' and condition is met → return true (show the field)
   478→  // If action is 'hide' and condition is met → return false (hide the field)
   479→  // If action is 'show' and condition is NOT met → return false (don't show)
   480→  // If action is 'hide' and condition is NOT met → return true (don't hide)
   481→  return rule.action === 'show' ? conditionMet : !conditionMet;
   482→}
   483→
   484→/**
   485→ * Evaluate dependent validation rules for a field
   486→ * Returns error message if validation fails, undefined otherwise
   487→ */
   488→function evaluateDependentValidation(
   489→  validation: DependentValidation,
   490→  fieldValue: any,
   491→  answers: Record<string, any>
   492→): string | undefined {
   493→  // First check if the condition is met
   494→  const conditionMet = evaluateConditionalRule(validation.condition, answers);
   495→
   496→  // If condition is not met, skip this validation
   497→  if (!conditionMet) {
   498→    return undefined;
   499→  }
   500→
   501→  // Condition is met, apply validation
   502→  switch (validation.type) {
   503→    case 'require_if':
   504→      if (fieldValue === undefined || fieldValue === null || fieldValue === '') {
   505→        return validation.validationRule.message;
   506→      }
   507→      if (Array.isArray(fieldValue) && fieldValue.length === 0) {
   508→        return validation.validationRule.message;
   509→      }
   510→      break;
   511→
   512→    case 'min_if':
   513→      if (Number(fieldValue) < Number(validation.validationRule.value)) {
   514→        return validation.validationRule.message;
   515→      }
   516→      break;
   517→
   518→    case 'max_if':
   519→      if (Number(fieldValue) > Number(validation.validationRule.value)) {
   520→        return validation.validationRule.message;
   521→      }
   522→      break;
   523→
   524→    case 'pattern_if':
   525→      if (validation.validationRule.value && typeof fieldValue === 'string') {
   526→        const regex = new RegExp(validation.validationRule.value);
   527→        if (!regex.test(fieldValue)) {
   528→          return validation.validationRule.message;
   529→        }
   530→      }
   531→      break;
   532→  }
   533→
   534→  return undefined;
   535→}
   536→
   537→/**
   538→ * Calculate quiz score based on correct answers
   539→ * Returns total score earned and maximum possible score
   540→ */
   541→function calculateQuizScore(
   542→  fields: FormField[],
   543→  answers: Record<string, any>
   544→): { score: number; maxScore: number } {
   545→  let score = 0;
   546→  let maxScore = 0;
   547→
   548→  fields.forEach((field) => {
   549→    // Skip fields without quiz settings
   550→    if (!field.quizSettings) {
   551→      return;
   552→    }
   553→
   554→    const { correctAnswer, points } = field.quizSettings;
   555→    const userAnswer = answers[field.id];
   556→
   557→    // Add to max possible score
   558→    maxScore += points;
   559→
   560→    // Check if answer is correct
   561→    const isCorrect = checkAnswerCorrect(field.type, userAnswer, correctAnswer);
   562→
   563→    if (isCorrect) {
   564→      score += points;
   565→    }
   566→  });
   567→
   568→  return { score, maxScore };
   569→}
   570→
   571→/**
   572→ * Check if user answer matches correct answer for a given field type
   573→ */
   574→function checkAnswerCorrect(
   575→  fieldType: FieldType,
   576→  userAnswer: any,
   577→  correctAnswer: unknown
   578→): boolean {
   579→  // Handle missing/empty answers
   580→  if (userAnswer === undefined || userAnswer === null || userAnswer === '') {
   581→    return false;
   582→  }
   583→
   584→  switch (fieldType) {
   585→    case 'text':
   586→    case 'textarea':
   587→      // Case-insensitive string comparison
   588→      return String(userAnswer).toLowerCase().trim() === String(correctAnswer).toLowerCase().trim();
   589→
   590→    case 'number':
   591→    case 'rating':
   592→    case 'scale':
   593→      // Numeric comparison
   594→      return Number(userAnswer) === Number(correctAnswer);
   595→
   596→    case 'date':
   597→    case 'time':
   598→      // Exact string comparison for dates/times
   599→      return String(userAnswer) === String(correctAnswer);
   600→
   601→    case 'select':
   602→    case 'radio':
   603→      // Exact match for single-select
   604→      return String(userAnswer) === String(correctAnswer);
   605→
   606→    case 'multiselect':
   607→      // Array comparison (order-independent)
   608→      if (!Array.isArray(userAnswer) || !Array.isArray(correctAnswer)) {
   609→        return false;
   610→      }
   611→      if (userAnswer.length !== correctAnswer.length) {
   612→        return false;
   613→      }
   614→      const sortedUser = [...userAnswer].sort();
   615→      const sortedCorrect = [...(correctAnswer as any[])].sort();
   616→      return sortedUser.every((val, idx) => val === sortedCorrect[idx]);
   617→
   618→    case 'checkbox':
   619→      // Boolean comparison
   620→      return Boolean(userAnswer) === Boolean(correctAnswer);
   621→
   622→    default:
   623→      return false;
   624→  }
   625→}
