      const sortedCorrect = [...(correctAnswer as any[])].sort();
      return sortedUser.every((val, idx) => val === sortedCorrect[idx]);

    case 'checkbox':
      // Boolean comparison
      return Boolean(userAnswer) === Boolean(correctAnswer);

    default:
      return false;
  }
}

