/**
 * Field Components
 * Individual field types for form rendering
 */

import { useState } from 'react';
import { Upload, X, FileIcon } from 'lucide-react';
import type { FormField, FileUploadAnswer } from '../../types/forms';

interface FieldComponentProps {
  field: FormField;
  value: any;
  onChange: (value: any) => void;
  error?: string;
}

export function TextField({ field, value, onChange, error }: FieldComponentProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
        </p>
      )}
      <input
        type="text"
        value={value || ''}
        onChange={(e) => onChange(e.target.value)}
        required={field.required}
        className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
      />
      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    </div>
  );
}

export function TextAreaField({ field, value, onChange, error }: FieldComponentProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
        </p>
      )}
      <textarea
        value={value || ''}
        onChange={(e) => onChange(e.target.value)}
        required={field.required}
        rows={4}
        className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
      />
      {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
    </div>
  );
}

export function NumberField({ field, value, onChange, error }: FieldComponentProps) {
  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
        {field.required && <span className="text-red-500 ml-1">*</span>}
      </label>
      {field.description && (
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
          {field.description}
        </p>
      )}
      <input
        type="number"
        value={value ?? ''}
        onChange={(e) => onChange(e.target.value ? Number(e.target.value) : null)}
        required={field.required}
