   354→export function FileUploadField({ field, value, onChange, error }: FieldComponentProps) {
   355→  const [uploadError, setUploadError] = useState<string>('');
   356→
   357→  // Default config if not specified
   358→  const config = field.fileConfig || {
   359→    maxSizeMB: 10,
   360→    allowedTypes: ['image/*', 'application/pdf'],
   361→    multiple: false,
   362→  };
   363→
   364→  const maxSizeBytes = config.maxSizeMB * 1024 * 1024;
   365→
   366→  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
   367→    const files = Array.from(e.target.files || []);
   368→    setUploadError('');
   369→
   370→    if (files.length === 0) return;
   371→
   372→    // Validate multiple files
   373→    if (!config.multiple && files.length > 1) {
   374→      setUploadError('Only one file is allowed');
   375→      e.target.value = ''; // Reset input
   376→      return;
   377→    }
   378→
   379→    // Validate each file
   380→    const validatedFiles: FileUploadAnswer[] = [];
   381→
   382→    for (const file of files) {
   383→      // Check file size
   384→      if (file.size > maxSizeBytes) {
   385→        setUploadError(`File "${file.name}" exceeds ${config.maxSizeMB}MB limit`);
   386→        e.target.value = '';
   387→        return;
   388→      }
   389→
   390→      // Check file type
   391→      const isAllowedType = config.allowedTypes.some((allowedType) => {
   392→        if (allowedType.endsWith('/*')) {
   393→          const category = allowedType.split('/')[0];
   394→          return file.type.startsWith(category + '/');
   395→        }
   396→        return file.type === allowedType;
   397→      });
   398→
   399→      if (!isAllowedType) {
   400→        setUploadError(
   401→          `File "${file.name}" type not allowed. Allowed types: ${config.allowedTypes.join(', ')}`
   402→        );
   403→        e.target.value = '';
   404→        return;
   405→      }
   406→
   407→      // Convert to base64
   408→      try {
   409→        const base64Data = await fileToBase64(file);
   410→        validatedFiles.push({
   411→          fileName: file.name,
   412→          fileType: file.type,
   413→          fileSize: file.size,
   414→          base64Data,
   415→          uploadedAt: new Date(),
   416→        });
   417→      } catch (err) {
   418→        setUploadError(`Failed to process file "${file.name}"`);
   419→        e.target.value = '';
   420→        return;
   421→      }
   422→    }
   423→
   424→    // Update value
   425→    if (config.multiple) {
   426→      // Append to existing files
   427→      const existingFiles = Array.isArray(value) ? value : [];
   428→      onChange([...existingFiles, ...validatedFiles]);
   429→    } else {
   430→      // Single file
   431→      onChange(validatedFiles[0]);
   432→    }
   433→
   434→    // Reset input so same file can be selected again
   435→    e.target.value = '';
   436→  };
   437→
   438→  const handleRemoveFile = (index?: number) => {
   439→    if (config.multiple && typeof index === 'number') {
   440→      const files = Array.isArray(value) ? value : [];
   441→      onChange(files.filter((_, i) => i !== index));
   442→    } else {
   443→      onChange(null);
   444→    }
   445→  };
   446→
   447→  // Get uploaded files as array
   448→  const uploadedFiles: FileUploadAnswer[] = config.multiple
   449→    ? Array.isArray(value)
   450→      ? value
   451→      : []
   452→    : value
   453→    ? [value]
   454→    : [];
   455→
   456→  return (
   457→    <div>
   458→      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   459→        {field.label}
   460→        {field.required && <span className="text-red-500 ml-1">*</span>}
   461→      </label>
   462→      {field.description && (
   463→        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
   464→          {field.description}
   465→        </p>
   466→      )}
   467→
   468→      {/* Upload Button */}
   469→      <div className="relative">
   470→        <input
   471→          type="file"
   472→          id={`file-${field.id}`}
   473→          onChange={handleFileChange}
   474→          multiple={config.multiple}
   475→          accept={config.allowedTypes.join(',')}
   476→          required={field.required && uploadedFiles.length === 0}
   477→          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
   478→        />
   479→        <div className="flex items-center gap-2 px-4 py-3 border-2 border-dashed border-border-light dark:border-border-dark rounded-lg hover:border-primary-light dark:hover:border-primary-dark transition-colors bg-surface-light dark:bg-surface-dark">
   480→          <Upload className="w-5 h-5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   481→          <div className="flex-1">
   482→            <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
   483→              {config.multiple ? 'Choose files or drag and drop' : 'Choose a file or drag and drop'}
   484→            </p>
   485→            <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   486→              Max {config.maxSizeMB}MB • {config.allowedTypes.join(', ')}
   487→            </p>
   488→          </div>
   489→        </div>
   490→      </div>
   491→
   492→      {/* Uploaded Files */}
   493→      {uploadedFiles.length > 0 && (
   494→        <div className="mt-3 space-y-2">
   495→          {uploadedFiles.map((file, index) => (
   496→            <div
   497→              key={index}
   498→              className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg"
   499→            >
   500→              <FileIcon className="w-5 h-5 text-primary-light dark:text-primary-dark shrink-0" />
   501→              <div className="flex-1 min-w-0">
   502→                <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary truncate">
   503→                  {file.fileName}
   504→                </p>
   505→                <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   506→                  {formatFileSize(file.fileSize)}
   507→                </p>
   508→              </div>
   509→              <button
   510→                type="button"
   511→                onClick={() => handleRemoveFile(config.multiple ? index : undefined)}
   512→                className="p-1 hover:bg-red-500/10 rounded transition-colors"
   513→                aria-label="Remove file"
   514→              >
   515→                <X className="w-4 h-4 text-red-500" />
   516→              </button>
   517→            </div>
   518→          ))}
   519→        </div>
   520→      )}
   521→
   522→      {/* Errors */}
   523→      {(uploadError || error) && (
   524→        <p className="text-xs text-red-500 mt-1">{uploadError || error}</p>
   525→      )}
   526→    </div>
   527→  );
   528→}
   529→
   530→// Helper: Convert file to base64
   531→function fileToBase64(file: File): Promise<string> {
   532→  return new Promise((resolve, reject) => {
   533→    const reader = new FileReader();
   534→    reader.onload = () => {
   535→      const result = reader.result as string;
   536→      // Remove data URL prefix (e.g., "data:image/png;base64,")
   537→      const base64 = result.split(',')[1];
   538→      resolve(base64);
   539→    };
   540→    reader.onerror = reject;
   541→    reader.readAsDataURL(file);
   542→  });
   543→}
   544→
   545→// Helper: Format file size
   546→function formatFileSize(bytes: number): string {
   547→  if (bytes === 0) return '0 Bytes';
   548→  const k = 1024;
   549→  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
   550→  const i = Math.floor(Math.log(bytes) / Math.log(k));
   551→  return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
   552→}
