  if (Array.isArray(value)) {
    return value.filter((v): v is FileUploadAnswer =>
      typeof v === 'object' && v !== null && 'fileName' in v
    );
  }
  if (value && typeof value === 'object' && 'fileName' in value) {
    return [value as FileUploadAnswer];
  }
  return [];
};

