export function FileUploadField({ field, value, onChange, error }: FieldComponentProps) {
  const [uploadError, setUploadError] = useState<string>('');

  // Default config if not specified
  const config = field.fileConfig || {
    maxSizeMB: 10,
    allowedTypes: ['image/*', 'application/pdf'],
    multiple: false,
  };

  const maxSizeBytes = config.maxSizeMB * 1024 * 1024;

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    setUploadError('');

    if (files.length === 0) return;

    // Validate multiple files
    if (!config.multiple && files.length > 1) {
      setUploadError('Only one file is allowed');
      e.target.value = ''; // Reset input
      return;
    }

    // Validate each file
    const validatedFiles: FileUploadAnswer[] = [];

    for (const file of files) {
      // Check file size
      if (file.size > maxSizeBytes) {
        setUploadError(`File "${file.name}" exceeds ${config.maxSizeMB}MB limit`);
        e.target.value = '';
        return;
      }

      // Check file type
      const isAllowedType = config.allowedTypes.some((allowedType) => {
        if (allowedType.endsWith('/*')) {
          const category = allowedType.split('/')[0];
          return file.type.startsWith(category + '/');
        }
        return file.type === allowedType;
      });

      if (!isAllowedType) {
        setUploadError(
          `File "${file.name}" type not allowed. Allowed types: ${config.allowedTypes.join(', ')}`
        );
        e.target.value = '';
        return;
      }

      // Convert to base64
      try {
        const base64Data = await fileToBase64(file);
        validatedFiles.push({
          fileName: file.name,
          fileType: file.type,
          fileSize: file.size,
          base64Data,
          uploadedAt: new Date(),
        });
      } catch (err) {
        setUploadError(`Failed to process file "${file.name}"`);
        e.target.value = '';
        return;
      }
    }

    // Update value
    if (config.multiple) {
      // Append to existing files
      const existingFiles = Array.isArray(value) ? value : [];
      onChange([...existingFiles, ...validatedFiles]);
    } else {
      // Single file
      onChange(validatedFiles[0]);
    }

    // Reset input so same file can be selected again
    e.target.value = '';
  };

  const handleRemoveFile = (index?: number) => {
    if (config.multiple && typeof index === 'number') {
      const files = Array.isArray(value) ? value : [];
      onChange(files.filter((_, i) => i !== index));
    } else {
      onChange(null);
    }
  };

  // Get uploaded files as array
  const uploadedFiles: FileUploadAnswer[] = config.multiple
    ? Array.isArray(value)
      ? value
      : []
    : value
    ? [value]
    : [];

  return (
    <div>
      <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
        {field.label}
