   433→                    onChange={(e) => setRecurrenceEndType(e.target.value as typeof recurrenceEndType)}
   434→                    className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
   435→                  >
   436→                    <option value="never">Never</option>
