   462→                      className="mt-1.5 w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
   463→                    />
   464→                  )}
   465→                </div>
   466→              )}
   467→            </>
   468→          )}
   469→
   470→          {/* Reminders */}
   471→          <div>
   472→            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
   473→              Reminders (Optional)
   474→            </label>
