   341→          </div>
   342→
   343→          {/* Progress Indicator */}
   344→          {exportProgress && (
   345→            <div className="p-4 rounded-lg bg-accent-blue/10 border border-accent-blue/30">
   346→              <div className="flex items-center gap-2 text-sm text-accent-blue">
   347→                <div className="w-4 h-4 border-2 border-accent-blue border-t-transparent rounded-full animate-spin" />
   348→                <span>{exportProgress}</span>
   349→              </div>
   350→            </div>
   351→          )}
   352→
   353→          {/* Error Message */}
   354→          {error && (
   355→            <div className="p-4 rounded-lg bg-red-500/10 border border-red-500/30">
   356→              <div className="flex items-start gap-2 text-sm text-red-500">
   357→                <AlertCircle className="w-4 h-4 mt-0.5 flex-shrink-0" />
   358→                <span>{error}</span>
   359→              </div>
   360→            </div>
   361→          )}
   362→        </div>
   363→
   364→        {/* Footer */}
   365→        <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-border-light dark:border-border-dark bg-surface-light-elevated dark:bg-surface-dark-elevated">
   366→          <button
   367→            onClick={onClose}
   368→            disabled={isExporting}
   369→            className="px-4 py-2 rounded-button text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-surface-dark transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
   370→          >
   371→            Cancel
   372→          </button>
   373→          <button
   374→            onClick={handleExport}
   375→            disabled={!canExport || isExporting}
   376→            className="px-4 py-2 rounded-button text-sm font-medium bg-accent-blue hover:bg-accent-blue-hover text-white transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
   377→          >
   378→            <FileDown className="w-4 h-4" />
   379→            Export Notes
   380→          </button>
   381→        </div>
   382→      </div>
   383→    </div>
   384→  );
   385→}
   386→

