                  key={form.id}
                  form={form}
                  onEdit={() => handleOpenBuilder(form.id)}
                  onFill={() => handleFillForm(form.id)}
                  onViewResponses={() => handleViewResponses(form.id)}
                  onDelete={() => handleDeleteForm(form.id)}
                  onDuplicate={() => handleDuplicateForm(form.id)}
                />
              ))}
            </div>
          )}
        </div>
      </main>
    </StoreErrorBoundary>
  );
}

// Form Card Component (Grid View)
interface FormCardProps {
  form: {
    id: string;
    title: string;
    description?: string;
    updatedAt: Date;
    fields: unknown[];
    responseCount: number;
    lastSubmittedAt?: Date;
  };
  onEdit: () => void;
  onFill: () => void;
  onViewResponses: () => void;
  onDelete: () => void;
  onDuplicate: () => void;
}

function FormCard({ form, onEdit, onFill, onViewResponses, onDelete, onDuplicate }: FormCardProps) {
  return (
    <div className="group bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg overflow-hidden hover:shadow-lg transition-shadow">
      {/* Header */}
      <div className="p-4 bg-gradient-to-br from-primary-light/10 to-primary-dark/10 dark:from-primary-dark/20 dark:to-primary-light/10">
        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary truncate mb-1">
          {form.title}
        </h3>
        {form.description && (
          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
            {form.description}
          </p>
        )}
      </div>

      {/* Stats */}
      <div className="p-4">
        <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary mb-3">
          <span>{form.fields.length} {form.fields.length === 1 ? 'field' : 'fields'}</span>
          <span>{form.responseCount} {form.responseCount === 1 ? 'response' : 'responses'}</span>
        </div>

        {/* Actions */}
        <div className="flex flex-col gap-2">
          <button
            onClick={onFill}
            className="w-full px-3 py-2 text-sm bg-primary-light dark:bg-primary-dark text-white rounded hover:opacity-90"
          >
            Fill Form
          </button>
          <div className="flex gap-2">
            <button
              onClick={onEdit}
              className="flex-1 px-2 py-1 text-xs bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
            >
              Edit
            </button>
            <button
              onClick={onViewResponses}
              className="flex-1 px-2 py-1 text-xs bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
            >
              Responses
            </button>
          </div>
          <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDuplicate();
              }}
              className="flex-1 px-2 py-1 text-xs bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
            >
              Duplicate
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDelete();
              }}
              className="flex-1 px-2 py-1 text-xs bg-red-500/10 text-red-500 rounded hover:bg-red-500/20"
            >
              Delete
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// Form List Item Component (List View)
function FormListItem({ form, onEdit, onFill, onViewResponses, onDelete, onDuplicate }: FormCardProps) {
  return (
    <div className="flex items-center gap-4 p-4 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg hover:shadow-md transition-shadow">
      {/* Icon */}
      <div className="w-12 h-12 bg-gradient-to-br from-primary-light/20 to-primary-dark/20 rounded flex items-center justify-center flex-shrink-0">
        <FileText className="w-6 h-6 text-primary-light dark:text-primary-dark" />
      </div>

      {/* Info */}
      <div className="flex-1 min-w-0">
        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
          {form.title}
        </h3>
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          {form.fields.length} fields • {form.responseCount} responses • Updated {new Date(form.updatedAt).toLocaleDateString()}
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-2">
        <button
          onClick={onFill}
          className="px-4 py-2 text-sm bg-primary-light dark:bg-primary-dark text-white rounded hover:opacity-90"
        >
          Fill Form
        </button>
        <button
          onClick={onEdit}
          className="px-3 py-2 text-sm bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
        >
          Edit
        </button>
        <button
          onClick={onViewResponses}
          className="px-3 py-2 text-sm bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
        >
          Responses
        </button>
        <button
          onClick={onDuplicate}
          className="px-3 py-2 text-sm bg-surface-hover-light dark:bg-surface-hover-dark rounded hover:bg-border-light dark:hover:bg-border-dark"
        >
          Duplicate
        </button>
        <button
          onClick={onDelete}
          className="px-3 py-2 text-sm bg-red-500/10 text-red-500 rounded hover:bg-red-500/20"
        >
          Delete
        </button>
      </div>
    </div>
  );
}

